/* eslint-disable max-classes-per-file */
import BigNumber from 'bignumber.js';
import elliptic from 'elliptic';

import { OneKeyLocalError } from '@onekeyhq/shared/src/errors';
import RN_QUICK_CRYPTO from '@onekeyhq/shared/src/modules3rdParty/react-native-quick-crypto';
import platformEnv from '@onekeyhq/shared/src/platformEnv';

import { parse256 } from '../bip32';

import type { IBaseCurve, ICurveForKD } from './base';

type IEllipticBasePoint = elliptic.curve.base.BasePoint;
type IQuickCryptoCurveName = 'secp256k1' | 'prime256v1';
type IQuickCryptoSetPrivateKeyInput = Parameters<
  ReturnType<typeof RN_QUICK_CRYPTO.createECDH>['setPrivateKey']
>[0];

function checkBufferIsNotEmpty(buff: Buffer) {
  if (buff?.length === 0) {
    throw new OneKeyLocalError('Curve call ERROR: Buffer is empty');
  }
}

function canUseQuickCryptoEC(): boolean {
  return Boolean(platformEnv.isNative) && !platformEnv.isJest;
}

function compressPublicKey(publicKey: Buffer): Buffer {
  if (publicKey.length === 33 && (publicKey[0] === 2 || publicKey[0] === 3)) {
    return publicKey;
  }
  if (publicKey.length !== 65 || publicKey[0] !== 4) {
    throw new OneKeyLocalError('Invalid public key.');
  }

  const compressedPublicKey = Buffer.alloc(33);
  compressedPublicKey[0] = publicKey[64] & 1 ? 3 : 2;
  publicKey.copy(compressedPublicKey, 1, 1, 33);
  return compressedPublicKey;
}

function publicFromPrivateByQuickCrypto({
  curveName,
  privateKey,
}: {
  curveName: IQuickCryptoCurveName;
  privateKey: Buffer;
}): Buffer {
  const ecdh = RN_QUICK_CRYPTO.createECDH(curveName);
  ecdh.setPrivateKey(privateKey as unknown as IQuickCryptoSetPrivateKeyInput);
  return compressPublicKey(
    Buffer.from(ecdh.getPublicKey() as unknown as Uint8Array),
  );
}

class EllipticECWrapper implements ICurveForKD {
  groupOrder: BigNumber;

  constructor(
    private curve: elliptic.ec,
    private quickCryptoCurveName?: IQuickCryptoCurveName,
  ) {
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    this.groupOrder = new BigNumber(curve.n!.toString());
  }

  transformPublicKey(publicKey: Buffer): Buffer {
    checkBufferIsNotEmpty(publicKey);

    let toCompressed: boolean;
    // eslint-disable-next-line eqeqeq
    if (publicKey.length == 33 && (publicKey[0] === 2 || publicKey[0] === 3)) {
      toCompressed = false;
      // eslint-disable-next-line eqeqeq
    } else if (publicKey.length == 65 && publicKey[0] === 4) {
      toCompressed = true;
    } else {
      throw new OneKeyLocalError('Invalid public key.');
    }

    return Buffer.from(
      this.curve
        .keyFromPublic(publicKey)
        .getPublic()
        .encode(undefined, toCompressed),
    );
  }

  publicFromPrivate(privateKey: Buffer): Buffer {
    checkBufferIsNotEmpty(privateKey);

    if (this.quickCryptoCurveName && canUseQuickCryptoEC()) {
      return publicFromPrivateByQuickCrypto({
        curveName: this.quickCryptoCurveName,
        privateKey,
      });
    }

    return Buffer.from(
      this.curve.keyFromPrivate(privateKey).getPublic().encodeCompressed(),
    );
  }

  verify(publicKey: Buffer, digest: Buffer, signature: Buffer): boolean {
    checkBufferIsNotEmpty(publicKey);
    checkBufferIsNotEmpty(signature);
    checkBufferIsNotEmpty(digest);

    // eslint-disable-next-line eqeqeq
    if (signature.length != 65) {
      return false;
    }
    return this.curve.keyFromPublic(publicKey).verify(digest, {
      r: signature.slice(0, 32),
      s: signature.slice(32, 64),
      recoveryParam: parseInt(signature[64].toString(), 10),
    });
  }

  sign(privateKey: Buffer, digest: Buffer): Buffer {
    checkBufferIsNotEmpty(privateKey);
    checkBufferIsNotEmpty(digest);

    const signature: elliptic.ec.Signature = this.curve
      .keyFromPrivate(privateKey)
      .sign(digest, { canonical: true });
    return Buffer.concat([
      signature.r.toArrayLike(Buffer, 'be', 32),
      signature.s.toArrayLike(Buffer, 'be', 32),
      // @ts-expect-error
      Buffer.from([signature.recoveryParam]),
    ]);
  }

  // https://github.com/bitcoin/bips/blob/master/bip-0032.mediawiki#public-parent-key--public-child-key
  getChildPublicKey(IL: Buffer, parentPublicKey: Buffer): Buffer | null {
    checkBufferIsNotEmpty(IL);
    checkBufferIsNotEmpty(parentPublicKey);

    if (parse256(IL).gte(this.groupOrder)) {
      return null;
    }
    const p: IEllipticBasePoint = this.curve.keyFromPrivate(IL).getPublic();
    const q: IEllipticBasePoint = this.curve
      .keyFromPublic(parentPublicKey)
      .getPublic();
    const r: IEllipticBasePoint = p.add(q);
    if (r.isInfinity()) {
      return null;
    }
    return Buffer.from(r.encodeCompressed());
  }
}

class EllipticEDDSAWrapper implements IBaseCurve {
  // eslint-disable-next-line no-useless-constructor
  constructor(private curve: elliptic.eddsa) {
    // noop
  }

  transformPublicKey(publicKey: Buffer): Buffer {
    checkBufferIsNotEmpty(publicKey);

    return publicKey;
  }

  publicFromPrivate(privateKey: Buffer): Buffer {
    checkBufferIsNotEmpty(privateKey);

    return Buffer.from(this.curve.keyFromSecret(privateKey).getPublic());
  }

  verify(publicKey: Buffer, digest: Buffer, signature: Buffer): boolean {
    checkBufferIsNotEmpty(publicKey);
    checkBufferIsNotEmpty(signature);
    checkBufferIsNotEmpty(digest);

    return this.curve
      .keyFromPublic(publicKey.toString('hex'))
      .verify(digest, signature.toString('hex'));
  }

  sign(privateKey: Buffer, digest: Buffer): Buffer {
    checkBufferIsNotEmpty(privateKey);
    checkBufferIsNotEmpty(digest);

    return Buffer.from(
      this.curve.keyFromSecret(privateKey).sign(digest).toBytes(),
    );
  }
}

const secp256k1: ICurveForKD = new EllipticECWrapper(
  // eslint-disable-next-line new-cap
  new elliptic.ec('secp256k1'),
  'secp256k1',
);
// eslint-disable-next-line new-cap
const nistp256: ICurveForKD = new EllipticECWrapper(
  // eslint-disable-next-line new-cap
  new elliptic.ec('p256'),
  'prime256v1',
);
const ed25519: IBaseCurve = new EllipticEDDSAWrapper(
  // eslint-disable-next-line new-cap
  new elliptic.eddsa('ed25519'),
);

export { ed25519, nistp256, secp256k1 };
