import { forwardRef } from 'react';
import type { ForwardedRef } from 'react';

import {
  ScaleDecorator,
  ShadowDecorator,
} from 'react-native-draggable-flatlist';

import { AnimatePresence } from '@onekeyhq/components/src/shared/tamagui';
import type {
  GetProps,
  StackProps,
  TamaguiElement,
} from '@onekeyhq/components/src/shared/tamagui';
import { ANIMATE_ONLY_OPACITY_TRANSFORM } from '@onekeyhq/components/src/utils/animationConstants';
import platformEnv from '@onekeyhq/shared/src/platformEnv';

import { IconButton } from '../../actions/IconButton';
import { Stack, XStack } from '../../primitives/Stack';

import type { PressableProps, View } from 'react-native';

const enterStyleAnimated = platformEnv.isNativeAndroid
  ? undefined
  : {
      opacity: 0,
      scale: 0,
    };

export type ISortableCellProps = StackProps & {
  isEditing?: boolean;
  shadowProps?: Omit<GetProps<typeof ShadowDecorator>, 'children'>;
  scaleProps?: Omit<GetProps<typeof ScaleDecorator>, 'children'>;
  pressableProps?: Omit<PressableProps, 'children'>;
  drag: () => void;
  isActive: boolean;
  onDeletePress?: () => void;
};

export type ISortableCellRef = View;

function BaseSortableCell(
  {
    isEditing = false,
    drag,
    shadowProps = {},
    scaleProps = { activeScale: 0.9 },
    onDeletePress,
    ...rest
  }: ISortableCellProps,
  ref: ForwardedRef<TamaguiElement> | undefined,
) {
  return (
    <ShadowDecorator {...shadowProps}>
      <ScaleDecorator {...scaleProps}>
        <XStack w="100%" alignItems="center">
          <AnimatePresence exitBeforeEnter>
            {isEditing ? (
              // Internal sortable-cell delete handle.
              // oxlint-disable-next-line onekey/require-testid
              <IconButton
                onPress={onDeletePress}
                icon="MinusCircleSolid"
                variant="destructive"
                animation="quick"
                animateOnly={ANIMATE_ONLY_OPACITY_TRANSFORM}
                enterStyle={enterStyleAnimated}
              />
            ) : null}
          </AnimatePresence>

          <Stack ref={ref} flex={1} {...rest} />

          {/* Don't use `Stack.onLongPress` as it will only be called after `onPressOut` */}
          <AnimatePresence exitBeforeEnter>
            {isEditing ? (
              // Internal sortable-cell drag handle.
              // oxlint-disable-next-line onekey/require-testid
              <IconButton
                icon="MenuOutline"
                onPressIn={drag}
                animation="quick"
                animateOnly={ANIMATE_ONLY_OPACITY_TRANSFORM}
                enterStyle={enterStyleAnimated}
              />
            ) : null}
          </AnimatePresence>
        </XStack>
      </ScaleDecorator>
    </ShadowDecorator>
  );
}

export const SortableCell = forwardRef(
  BaseSortableCell,
) as typeof BaseSortableCell;
